import React, { useState, useEffect } from "react";
import ProductDetails from "../ProductDetails/ProductDetails"; // تأكد من المسار الصحيح
import "./Biscuits.css";

const commonStyles = {
  container: "layout_container",
  headerWrapper: "Header_wrapper",
  headerSubtitle: "Header_subtitle",
  headerTitle: "Header_title",
};

const SectionHeader = ({ title, subtitle }) => (
  <div className={commonStyles.headerWrapper}>
    <span className={commonStyles.headerSubtitle}>{subtitle}</span>
    <h2 className={commonStyles.headerTitle}>{title}</h2>
  </div>
);

const Biscuits = () => {
  const [activeFilter, setActiveFilter] = useState("marshmallow");
  const [selectedProduct, setSelectedProduct] = useState(null); // حالة المنتج المختار

  const filters = [
    { id: "marshmallow", label: "بسكويت مع مارشميلو" },
    { id: "coated", label: "بسكويت مغطس" },
    { id: "jelly", label: "بسكويت مع الجيلي" },
    { id: "cream", label: "بسكويت محشي بالكريمة" },
  ];

  const products = [
    {
      id: 1,
      name: "Hugy Puff",
      category: "marshmallow",
      description: "بسكويت مع المارشميلو مغطى بالفارماسيل",
      weight: "24g",
      packaging: "مغلف آلياً",
      ingredients: [
        "دقيق الطحين",
        "سكر",
        "جلكوز ",
        "زيوت نباتية مهدرجة بالكامل",
        "حليب خالي الدسم بودرة",
        "مصل الحليب",
        "سوربيتول E420",
        "جيلاتين بقري",
        "ليستين الصويا (مستحلب E322)",
        "غليسرين ",
        "مواد رافعة (بيروفوسفات الصوديوم E450-1 , بيكربونات الصوديوم , بيكربونات الامونيوم)",
        "مواد حافظة (سوربات البوتاسيوم E202)",
        "ملح الطعام",
        "منكهات مماثلة للطبيعة",
        "مونوغلسرايد",
      ],
      images: [
        "/images/Product19/HuggyPuff1.webp",
        "/images/Product19/HuggyPuff2.webp",
        "/images/Product19/HuggyPuff3.webp",
      ],
      img: "/images/Product19/HuggyPuffEaten.webp",
    },
    {
      id: 2,
      name: "Bisco Moosh",
      category: "marshmallow",
      description:
        "بسكويت فاخر محشي بالمارشميللو الناعم ومغطس بطبقة غنية من الشوكولا الداكنة.",
      weight: "40g",
      packaging: "مغلف آلياً",
      ingredients: ["طحين", "شوكولا", "مارشميلو"],
      images: [
        "/images/Product6/BiscoMoosh1.webp",
        "/images/Product6/BiscoMoosh2.webp",
        "/images/Product6/BiscoMoosh3.webp",
      ],
      img: "/images/Product6/BiscoMooshEaten.webp",
    },
    // يمكنك إضافة تفاصيل (price, images, ingredients) لبقية المنتجات هنا بنفس الطريقة
    {
      id: 3,
      name: "Histeria Max",
      category: "coated",
      description:
        "بسكويت دبل محشي كريمة الشوكولا الغنية ومغطس بالكامل بالشوكولا السويسرية.",
      weight: "50g",
      packaging: "صندوق كرتوني",
      ingredients: ["طحين", "زبدة كاكاو", "حليب"],
      images: [
        "/images/Product1/HisteriaMax1.webp",
        "/images/Product1/HisteriaMax2.webp",
        "/images/Product1/HisteriaMax3.webp",
      ],
      img: "/images/Product1/HisteriaMaxEaten.webp",
    },
    {
      id: 4,
      name: "Opaliz",
      category: "coated",
      description: "بسكويت مع الكراميل المغطس بالشوكولا",
      weight: "50g",
      packaging: "صندوق كرتوني",
      ingredients: ["طحين", "زبدة كاكاو", "حليب"],
      images: [
        "/images/Product4/Opaliz1.webp",
        "/images/Product4/Opaliz2.webp",
        "/images/Product4/Opaliz3.webp",
      ],
      img: "/images/Product4/OpalizEaten.webp",
    },
    {
      id: 5,
      name: "Bisco Jell Orange",
      category: "jelly",
      description: "بسكويت مع جيلي البرتقال",
      img: "/images/Product7/BiscojellOrangeEaten.webp",
    },
    {
      id: 6,
      name: "Bisco Jell Berry",
      category: "jelly",
      description: "بسكويت مع جيلي التوت",
      img: "/images/Product8/BiscojellBerryEaten.webp",
    },
    {
      id: 7,
      name: "Bisco Jell Strawberry",
      category: "jelly",
      description: "بسكويت مع جيلي الفريز",
      img: "/images/Product9/BiscojellStrawberryEaten.webp",
    },
    {
      id: 8,
      name: "Bisco Jell Apricot",
      category: "jelly",
      description: "بسكويت مع جيي المشمش",
      img: "/images/Product10/BiscojellApricotEaten.webp",
    },
    {
      id: 9,
      name: "Bisco Max",
      category: "cream",
      description: "بسكويت الكاكاو محشي بكريم الحليب",
      img: "/images/Product12/BiscoMaxChocoEaten.webp",
    },
    {
      id: 10,
      name: "Bisco Max",
      category: "cream",
      description: "بسكويت الحليب محشي بكريم الشوكولا",
      img: "/images/Product13/BiscoMaxChocoCreamEaten.webp",
    },
    {
      id: 11,
      name: "Bisco Max",
      category: "cream",
      description: "بسكويت الكاكاو محشي بكريم الحليب",
      img: "/images/Product14/BiscoMaxCocoaBiscuitEaten.webp",
    },
    {
      id: 12,
      name: "Bisco Max",
      category: "cream",
      description: "بسكويت الكاكاو محشي بكريم الشوكولا",
      img: "/images/Product15/BiscoMaxChocoBiscuitEaten.webp",
    },
    {
      id: 13,
      name: "Bisco Max",
      category: "cream",
      description: "بسكويت الحليب محشي بكريم الفريز",
      img: "/images/Product16/BiscoMaxStrawberryCreamEaten.webp",
    },
    {
      id: 14,
      name: "Bisco Max",
      category: "cream",
      description: "بسكويت القهوة محشي بكريم القهوة",
      img: "/images/Product17/BiscoMaxCoffeeEaten.webp",
    },
    {
      id: 15,
      name: "Bisco Max",
      category: "cream",
      description: "بسكويت الكراميل محشي بكريم الكراميل",
      img: "/images/Product18/BiscoMaxCaramelEaten.webp",
    },
    {
      id: 16,
      name: "Bisco Max Choco",
      category: "cream",
      description: "بسكويت الكاكاو محشي بكريم الحليب",
      img: "/images/Product11/BiscoMaxOrangeEaten.webp",
    },
  ];

  const filteredProducts = products.filter((p) => p.category === activeFilter);

  useEffect(() => {
    if (!selectedProduct) {
      const observerOptions = { threshold: 0.1 };
      const observer = new IntersectionObserver((entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add("is-visible");
          }
        });
      }, observerOptions);

      const cards = document.querySelectorAll(".Catalog_card");
      cards.forEach((card) => observer.observe(card));
      return () => observer.disconnect();
    }
  }, [filteredProducts, selectedProduct]);

  // إذا كان هناك منتج مختار، اعرض صفحة التفاصيل
  if (selectedProduct) {
    return (
      <ProductDetails
        product={selectedProduct}
        onBack={() => setSelectedProduct(null)}
      />
    );
  }

  return (
    <div className="biscuit-container">
      <div className={commonStyles.container}>
        <SectionHeader title="تصفح منتجات البسكويت" subtitle="جودة وفخامة" />

        <div className="Catalog_filterWrapper">
          {filters.map((filter) => (
            <button
              key={filter.id}
              className={`Catalog_filterBtn ${
                activeFilter === filter.id ? "Catalog_filterBtnActive" : ""
              }`}
              onClick={() => setActiveFilter(filter.id)}
            >
              {filter.label}
            </button>
          ))}
        </div>

        <div className="Catalog_grid">
          {filteredProducts.map((product) => (
            <div
              key={product.id}
              className="Catalog_card"
              onClick={() => setSelectedProduct(product)} // عند النقر، يتم اختيار المنتج
              style={{ cursor: "pointer" }}
            >
              <div className="Catalog_imgContainer">
                <img
                  src={product.img}
                  alt={product.name}
                  className="Catalog_img"
                />
              </div>
              <div className="Catalog_info">
                <h4 className="Catalog_name">{product.name}</h4>
                <div className="Catalog_desc">
                  <p>{product.description}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Biscuits;
